import React, { useState, useMemo, useEffect } from 'react';
import {
  LayoutDashboard, Tractor, PackageSearch,
  Wrench, Settings, Sprout, TrendingUp, ShoppingCart, AlertTriangle, ShieldCheck, User
} from 'lucide-react';
import { useAuth } from './context/AuthContext';
import { useFirestore } from './hooks/useFirestore';
import { Card, cn, Spinner } from './components/ui';
import { ProductoresManager, ClientesManager, VariedadesManager } from './components/ConfigModules';
import { HuertasSection, ManejosSection } from './components/ProduccionModules';
import { EquipoSection, MantenimientosSection } from './components/EquiposModules';
import { EntradasSection, ConsolidadorSection, SalidasSection } from './components/BodegaModules';
import Login from './components/Login';
import { AccountModule } from './components/AccountModule';
import { AdminModules } from './components/AdminModules';


/* ─── Nav Item ─────────────────── */
function NavItem({ icon: Icon, label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "flex items-center gap-3 px-4 py-3 rounded-xl transition-all w-full text-left whitespace-nowrap",
        active
          ? "bg-green-600 text-white shadow-lg shadow-green-900/30"
          : "text-slate-400 hover:bg-slate-800 hover:text-white"
      )}
    >
      <Icon className="w-5 h-5 flex-shrink-0" />
      <span className="font-medium text-sm">{label}</span>
    </button>
  );
}

/* ─── Dashboard ─────────────────── */
function Dashboard({ entradas, detalles, detalleSalidas, mantenimientos, equipo }) {
  const today = new Date().toISOString().split('T')[0];

  const ventasHoy = useMemo(() => {
    const ids = new Set(
      detalleSalidas
        .filter(ds => {
          // We check the salida's fecha — approximate by looking at detalle
          return true; // done via parent joining below
        })
        .map(ds => ds.id)
    );
    return 0; // calculated below
  }, [detalleSalidas]);

  const ventasHoyTotal = useMemo(() => {
    return detalleSalidas.reduce((sum, ds) => sum + (ds.precio_dia * ds.cantidad_vendida || 0), 0);
  }, [detalleSalidas]);

  const tarimasEnInventario = useMemo(() =>
    detalles.filter(d => d.status === 'almacenada' || d.status === 'en_proceso').length,
    [detalles]
  );

  const proximosMantenimientos = useMemo(() => {
    const now = new Date();
    return mantenimientos
      .filter(m => new Date(m.fecha) >= now)
      .sort((a, b) => new Date(a.fecha) - new Date(b.fecha))
      .slice(0, 3);
  }, [mantenimientos]);

  const entradasPendientes = useMemo(() =>
    entradas.filter(e => e.status === 'pendiente').length,
    [entradas]
  );

  const kpis = [
    {
      label: "Ventas Registradas",
      value: `$${ventasHoyTotal.toFixed(0)}`,
      sub: `${detalleSalidas.length} partidas`,
      icon: TrendingUp,
      color: "bg-green-50 text-green-600",
    },
    {
      label: "Tarimas en Bodega",
      value: tarimasEnInventario,
      sub: `${detalles.filter(d => d.status === 'almacenada').length} almacenadas`,
      icon: PackageSearch,
      color: "bg-blue-50 text-blue-600",
    },
    {
      label: "Entradas Pendientes",
      value: entradasPendientes,
      sub: "Por liquidar al productor",
      icon: AlertTriangle,
      color: "bg-yellow-50 text-yellow-600",
    },
    {
      label: "Equipos Registrados",
      value: equipo.length,
      sub: `${mantenimientos.length} mantenimientos`,
      icon: Wrench,
      color: "bg-purple-50 text-purple-600",
    },
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">Dashboard</h1>
        <p className="text-sm text-slate-500 mt-1">Sistema Integral · Barredora de Tunas</p>
      </div>

      <div className="grid grid-cols-2 xl:grid-cols-4 gap-4">
        {kpis.map((kpi, i) => (
          <Card key={i} className="flex flex-col gap-3">
            <div className="flex justify-between items-start">
              <div>
                <p className="text-xs font-medium text-slate-500">{kpi.label}</p>
                <h2 className="text-2xl font-bold text-slate-900 mt-1">{kpi.value}</h2>
                <p className="text-xs text-slate-400 mt-0.5">{kpi.sub}</p>
              </div>
              <div className={cn("p-2.5 rounded-xl", kpi.color)}>
                <kpi.icon className="w-5 h-5" />
              </div>
            </div>
          </Card>
        ))}
      </div>

      {/* Upcoming maintenance */}
      {proximosMantenimientos.length > 0 && (
        <Card>
          <h3 className="font-semibold text-slate-900 mb-3">Próximos Mantenimientos</h3>
          <div className="space-y-2">
            {proximosMantenimientos.map(m => {
              const eq = equipo.find(e => e.id === m.equipo_id);
              return (
                <div key={m.id} className="flex items-center justify-between bg-orange-50 rounded-xl px-4 py-3">
                  <div>
                    <p className="text-sm font-medium text-slate-800">{eq?.nombre || '–'}</p>
                    <p className="text-xs text-slate-500">{m.tipo_mantenimiento} · {m.descripcion}</p>
                  </div>
                  <span className="text-sm font-semibold text-orange-600">{m.fecha}</span>
                </div>
              );
            })}
          </div>
        </Card>
      )}

      {/* Recent tarimas */}
      <Card>
        <h3 className="font-semibold text-slate-900 mb-3">Estado de Tarimas</h3>
        <div className="grid grid-cols-3 gap-4 text-center">
          {['almacenada', 'en_proceso', 'completa'].map(st => {
            const count = detalles.filter(d => d.status === st).length;
            const styleMap = { almacenada: 'bg-blue-50 text-blue-700', en_proceso: 'bg-orange-50 text-orange-700', completa: 'bg-green-50 text-green-700' };
            const labels = { almacenada: 'Almacenadas', en_proceso: 'En Proceso', completa: 'Completas' };
            return (
              <div key={st} className={cn("rounded-xl p-4", styleMap[st])}>
                <p className="text-3xl font-bold">{count}</p>
                <p className="text-xs font-medium mt-1">{labels[st]}</p>
              </div>
            );
          })}
        </div>
      </Card>
    </div>
  );
}

/* ─── Tabs sub-nav ─────────────── */
function TabNav({ tabs, active, onChange }) {
  return (
    <div className="flex gap-1 bg-slate-100 rounded-xl p-1 mb-6 overflow-x-auto">
      {tabs.map(t => (
        <button key={t.key} onClick={() => onChange(t.key)}
          className={cn(
            "flex-1 min-w-max px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap",
            active === t.key ? "bg-white text-slate-900 shadow-sm" : "text-slate-500 hover:text-slate-700"
          )}>
          {t.label}
        </button>
      ))}
    </div>
  );
}

/* ─── Root App ─────────────────── */
export default function App() {
  const { user, userData, activeTenant, setActiveTenant } = useAuth();
  const isAdmin = userData?.rol === 'admin';
  const [activeTab, setActiveTab] = useState('dashboard');

  // Update default tab based on role once userData is loaded
  useEffect(() => {
    if (activeTenant && activeTab === 'admin') setActiveTab('dashboard');
    else if (!activeTenant && isAdmin) setActiveTab('admin');
    else if (!isAdmin && user && activeTab === 'admin') setActiveTab('dashboard');
  }, [isAdmin, user, activeTenant]);

  const [subTab, setSubTab] = useState({
    produccion: 'huertas',
    bodega: 'entradas',
    equipos: 'equipos',
    config: 'productores',
  });

  const { data: productores } = useFirestore('productores');
  const { data: clientes } = useFirestore('clientes');
  const { data: variedades } = useFirestore('variedades');
  const { data: huertas } = useFirestore('huertas');
  const { data: entradas } = useFirestore('registro_entradas');
  const { data: detalles } = useFirestore('detalle_entradas');
  const { data: detalleSalidas } = useFirestore('detalle_salidas');
  const { data: equipo } = useFirestore('equipo');
  const { data: mantenimientos } = useFirestore('mantenimientos');

  const setTab = (module, tab) => setSubTab(p => ({ ...p, [module]: tab }));

  if (!user) return <Login />;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-60 bg-slate-900 text-slate-300 flex flex-col flex-shrink-0 z-10 shadow-xl">
        <div className="p-5 border-b border-slate-800 flex items-center gap-3">
          <div className="p-2 bg-green-600 rounded-xl">
            <Sprout className="w-6 h-6 text-white" />
          </div>
          <div>
            <p className="text-base font-bold text-white leading-tight">Tunas</p>
            <p className="text-xs text-slate-400">Sweeper System</p>
          </div>
        </div>

        <nav className="p-3 flex flex-row md:flex-col gap-1 overflow-x-auto md:overflow-visible flex-1">
          {isAdmin && (
            <NavItem
              icon={ShieldCheck}
              label="Super Admin"
              active={activeTab === 'admin' && !activeTenant}
              onClick={() => { setActiveTenant(null); setActiveTab('admin'); }}
            />
          )}

          {(!isAdmin || activeTenant) && (
            <>
              <NavItem icon={LayoutDashboard} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
              <NavItem icon={Tractor} label="Producción" active={activeTab === 'produccion'} onClick={() => setActiveTab('produccion')} />
              <NavItem icon={PackageSearch} label="Bodega" active={activeTab === 'bodega'} onClick={() => setActiveTab('bodega')} />
              <NavItem icon={Wrench} label="Equipos" active={activeTab === 'equipos'} onClick={() => setActiveTab('equipos')} />
              <NavItem icon={Settings} label="Configuración" active={activeTab === 'config'} onClick={() => setActiveTab('config')} />
            </>
          )}
        </nav>

        <div className="hidden md:block mt-auto p-4 border-t border-slate-800">
          {!isAdmin && <NavItem icon={User} label="Mi Cuenta" active={activeTab === 'cuenta'} onClick={() => setActiveTab('cuenta')} />}
          <p className="text-xs text-slate-500 mt-4 px-2">Barredora de Tunas © 2026</p>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {activeTenant && (
          <div className="bg-orange-600 text-white px-4 md:px-8 py-3 flex justify-between items-center shadow-md z-10">
            <span className="font-medium text-sm flex items-center">
              <AlertTriangle className="w-5 h-5 mr-3 flex-shrink-0" />
              <span>
                Vista Administrador — Gestionando a: <strong className="ml-1">{activeTenant.email}</strong> {activeTenant.nombre ? `(${activeTenant.nombre})` : ''}
              </span>
            </span>
            <button
              className="bg-white/20 hover:bg-white/30 text-white text-xs font-semibold px-4 py-2 rounded-lg transition-colors ml-4 whitespace-nowrap"
              onClick={() => { setActiveTenant(null); setActiveTab('admin'); }}
            >
              Cerrar Gestión
            </button>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          {activeTab === 'dashboard' && (
            <Dashboard
              entradas={entradas} detalles={detalles}
              detalleSalidas={detalleSalidas} mantenimientos={mantenimientos} equipo={equipo}
            />
          )}

          {activeTab === 'produccion' && (
            <div>
              <h1 className="text-2xl font-bold text-slate-900 mb-5">Producción</h1>
              <TabNav
                tabs={[{ key: 'huertas', label: 'Huertas' }, { key: 'manejos', label: 'Manejos de Campo' }]}
                active={subTab.produccion} onChange={t => setTab('produccion', t)}
              />
              {subTab.produccion === 'huertas' && <HuertasSection variedades={variedades} />}
              {subTab.produccion === 'manejos' && <ManejosSection huertas={huertas} variedades={variedades} />}
            </div>
          )}

          {activeTab === 'bodega' && (
            <div>
              <h1 className="text-2xl font-bold text-slate-900 mb-5">Bodega & Ventas</h1>
              <TabNav
                tabs={[
                  { key: 'entradas', label: 'Entradas' },
                  { key: 'consolidador', label: 'Consolidador de Carga' },
                  { key: 'salidas', label: 'Historial Salidas' },
                ]}
                active={subTab.bodega} onChange={t => setTab('bodega', t)}
              />
              {subTab.bodega === 'entradas' && <EntradasSection productores={productores} variedades={variedades} />}
              {subTab.bodega === 'consolidador' && <ConsolidadorSection clientes={clientes} variedades={variedades} />}
              {subTab.bodega === 'salidas' && <SalidasSection clientes={clientes} variedades={variedades} />}
            </div>
          )}

          {activeTab === 'equipos' && (
            <div>
              <h1 className="text-2xl font-bold text-slate-900 mb-5">Equipos & Maquinaria</h1>
              <TabNav
                tabs={[{ key: 'equipos', label: 'Equipos' }, { key: 'historial', label: 'Historial Mantenimientos' }]}
                active={subTab.equipos} onChange={t => setTab('equipos', t)}
              />
              {subTab.equipos === 'equipos' && <EquipoSection />}
              {subTab.equipos === 'historial' && <MantenimientosSection />}
            </div>
          )}

          {activeTab === 'config' && !isAdmin && (
            <div>
              <h1 className="text-2xl font-bold text-slate-900 mb-5">Configuración</h1>
              <TabNav
                tabs={[
                  { key: 'productores', label: 'Productores' },
                  { key: 'clientes', label: 'Clientes' },
                  { key: 'variedades', label: 'Variedades' },
                ]}
                active={subTab.config} onChange={t => setTab('config', t)}
              />
              {subTab.config === 'productores' && <ProductoresManager />}
              {subTab.config === 'clientes' && <ClientesManager />}
              {subTab.config === 'variedades' && <VariedadesManager />}
            </div>
          )}

          {activeTab === 'cuenta' && !isAdmin && <AccountModule />}
          {activeTab === 'admin' && isAdmin && !activeTenant && <AdminModules />}
        </div>
      </main>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Plus, PackageSearch, ShoppingCart, CheckCircle, ArrowRight, Trash2 } from 'lucide-react';
import { useFirestore } from '../hooks/useFirestore';
import {
    Card, Button, Input, Select, Modal, Textarea, RadioGroup,
    ErrorBanner, SuccessBanner, EmptyState, Spinner, SectionHeader, StatusBadge, cn
} from './ui';

/* ── Entradas (Recepciones de Tarimas) ── */
export function EntradasSection({ productores, variedades }) {
    const { data: entradas, loading, error, addNode, updateNode } = useFirestore('registro_entradas');
    const { data: detalles, addNode: addDetalle } = useFirestore('detalle_entradas');
    const [entradaModal, setEntradaModal] = useState(false);
    const [tarimaModal, setTarimaModal] = useState(null); // entradaId
    const [form, setForm] = useState({});
    const [tForm, setTForm] = useState({});
    const [saving, setSaving] = useState(false);
    const [formError, setFormError] = useState('');
    const [success, setSuccess] = useState('');

    const handleSaveEntrada = async () => {
        if (!form.productor_id || !form.fecha) { setFormError('Productor y fecha son requeridos.'); return; }
        setSaving(true); setFormError('');
        try {
            await addNode({ ...form, monto_total_productor: 0, status: 'pendiente' });
            setEntradaModal(false); setSuccess('Entrada registrada.'); setTimeout(() => setSuccess(''), 3000);
        } catch (e) { setFormError(e.message); }
        finally { setSaving(false); }
    };

    const handleSaveTarima = async () => {
        if (!tForm.variedad_id || !tForm.tarima_no || !tForm.cantidad_recibida) {
            setFormError('Variedad, # tarima y cantidad son requeridos.'); return;
        }
        setSaving(true); setFormError('');
        try {
            await addDetalle({
                registro_entrada_id: tarimaModal,
                ...tForm,
                cantidad_vendida: 0,
                merma: 0,
                status: 'almacenada',
            });
            setTarimaModal(null); setSuccess('Tarima registrada.'); setTimeout(() => setSuccess(''), 3000);
        } catch (e) { setFormError(e.message); }
        finally { setSaving(false); }
    };

    const getDetalles = (entradaId) => detalles.filter(d => d.registro_entrada_id === entradaId);
    const getProductor = (id) => productores.find(p => p.id === id);

    return (
        <div className="space-y-4">
            <SectionHeader title="Entradas de Producto"
                action={<Button onClick={() => { setForm({ fecha: new Date().toISOString().split('T')[0] }); setFormError(''); setEntradaModal(true); }}>
                    <Plus className="w-4 h-4" /> Nueva Entrada
                </Button>} />
            <ErrorBanner error={error} /><SuccessBanner message={success} />
            {loading ? <Spinner /> : entradas.length === 0 ? <EmptyState icon={PackageSearch} message="Sin entradas registradas" /> : (
                <div className="space-y-3">
                    {[...entradas].sort((a, b) => new Date(b.fecha) - new Date(a.fecha)).map(e => {
                        const ds = getDetalles(e.id);
                        const prod = getProductor(e.productor_id);
                        return (
                            <Card key={e.id}>
                                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                                    <div>
                                        <div className="flex items-center gap-2 mb-1">
                                            <p className="font-semibold text-slate-900">{prod?.nombre || 'Productor eliminado'}</p>
                                            <StatusBadge status={e.status} />
                                        </div>
                                        <p className="text-sm text-slate-500">📅 {e.fecha} · {ds.length} tarima(s)</p>
                                        <p className="text-sm text-slate-500">Monto productor: <span className="font-semibold text-green-700">${(e.monto_total_productor || 0).toFixed(2)}</span></p>
                                    </div>
                                    <div className="flex gap-2">
                                        <Button variant="outline" className="text-sm" onClick={() => { setTForm({ presentacion: variedades[0]?.presentacion_default || '' }); setFormError(''); setTarimaModal(e.id); }}>
                                            <Plus className="w-4 h-4" /> Tarima
                                        </Button>
                                        {e.status === 'pendiente' && (
                                            <Button variant="yellow" className="text-sm" onClick={() => updateNode(e.id, { status: 'pagado' })}>
                                                ✓ Liquidar
                                            </Button>
                                        )}
                                    </div>
                                </div>
                                {ds.length > 0 && (
                                    <div className="mt-3 pt-3 border-t border-slate-100 overflow-x-auto">
                                        <table className="w-full text-sm min-w-[500px]">
                                            <thead>
                                                <tr className="text-xs text-slate-400 uppercase">
                                                    <th className="text-left pb-2">Tarima #</th>
                                                    <th className="text-left pb-2">Variedad</th>
                                                    <th className="text-right pb-2">Recibido</th>
                                                    <th className="text-right pb-2">Vendido</th>
                                                    <th className="text-right pb-2">Merma</th>
                                                    <th className="text-left pb-2">Status</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-slate-100">
                                                {ds.map(d => (
                                                    <tr key={d.id}>
                                                        <td className="py-1.5 font-mono text-slate-700">{d.tarima_no}</td>
                                                        <td className="py-1.5 text-slate-600">{variedades.find(v => v.id === d.variedad_id)?.nombre}</td>
                                                        <td className="py-1.5 text-right text-slate-700">{d.cantidad_recibida}</td>
                                                        <td className="py-1.5 text-right text-green-600">{d.cantidad_vendida}</td>
                                                        <td className="py-1.5 text-right text-orange-500">{d.merma}</td>
                                                        <td className="py-1.5"><StatusBadge status={d.status} /></td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                )}
                            </Card>
                        );
                    })}
                </div>
            )}

            {/* Modal nueva entrada */}
            <Modal open={entradaModal} onClose={() => setEntradaModal(false)} title="Nueva Entrada de Producto">
                <div className="space-y-4">
                    <ErrorBanner error={formError} />
                    <Select label="Productor" options={productores.map(p => ({ value: p.id, label: p.nombre }))} value={form.productor_id || ''} onChange={e => setForm(p => ({ ...p, productor_id: e.target.value }))} />
                    <Input label="Fecha de recepción" type="date" value={form.fecha || ''} onChange={e => setForm(p => ({ ...p, fecha: e.target.value }))} />
                    <div className="flex justify-end gap-2 pt-2">
                        <Button variant="secondary" onClick={() => setEntradaModal(false)}>Cancelar</Button>
                        <Button loading={saving} onClick={handleSaveEntrada}>Registrar Entrada</Button>
                    </div>
                </div>
            </Modal>

            {/* Modal nueva tarima */}
            <Modal open={!!tarimaModal} onClose={() => setTarimaModal(null)} title="Agregar Tarima">
                <div className="space-y-4">
                    <ErrorBanner error={formError} />
                    <Input label="# Tarima" value={tForm.tarima_no || ''} onChange={e => setTForm(p => ({ ...p, tarima_no: e.target.value }))} />
                    <Select label="Variedad" options={variedades.map(v => ({ value: v.id, label: v.nombre }))} value={tForm.variedad_id || ''} onChange={e => setTForm(p => ({ ...p, variedad_id: e.target.value }))} />
                    <Input label="Cantidad recibida (cajas)" type="number" value={tForm.cantidad_recibida || ''} onChange={e => setTForm(p => ({ ...p, cantidad_recibida: Number(e.target.value) }))} />
                    <RadioGroup
                        label="Presentación"
                        options={[
                            { value: 'Caja', label: 'Caja', icon: '📦' },
                            { value: 'Kilo', label: 'Kilo', icon: '⚖️' }
                        ]}
                        value={tForm.presentacion || ''}
                        onChange={val => setTForm(p => ({ ...p, presentacion: val }))}
                    />
                    <Input label="Precio sugerido de venta ($)" type="number" value={tForm.precio_venta_sugerido || ''} onChange={e => setTForm(p => ({ ...p, precio_venta_sugerido: Number(e.target.value) }))} />
                    <div className="flex justify-end gap-2 pt-2">
                        <Button variant="secondary" onClick={() => setTarimaModal(null)}>Cancelar</Button>
                        <Button loading={saving} onClick={handleSaveTarima}>Agregar Tarima</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

/* ── Consolidador de Carga (Carrito de Salida) ── */
export function ConsolidadorSection({ clientes, variedades }) {
    const { data: detalles, updateNode: updateDetalle } = useFirestore('detalle_entradas');
    const { data: entradas } = useFirestore('registro_entradas');
    const { addNode: addSalida, updateNode: updateEntrada } = useFirestore('registro_salidas');
    const { addNode: addDetalleSalida } = useFirestore('detalle_salidas');

    const [cart, setCart] = useState([]); // Array of {detalleEntrada, cantidad, precio_dia}
    const [clienteId, setClienteId] = useState('');
    const [fecha, setFecha] = useState(new Date().toISOString().split('T')[0]);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    // Only show disponibles (almacenada or en_proceso)
    const disponibles = useMemo(() =>
        detalles.filter(d => d.status === 'almacenada' || d.status === 'en_proceso'),
        [detalles]
    );

    const inCart = (id) => cart.find(c => c.detalle.id === id);

    const addToCart = (det) => {
        if (inCart(det.id)) return;
        const variedad = variedades.find(v => v.id === det.variedad_id);
        setCart(p => [...p, { detalle: det, cantidad: det.cantidad_recibida - det.cantidad_vendida - det.merma, precio_dia: variedad?.precio_venta || 0 }]);
    };

    const removeFromCart = (id) => setCart(p => p.filter(c => c.detalle.id !== id));

    const updateCartItem = (id, field, val) => setCart(p => p.map(c => c.detalle.id === id ? { ...c, [field]: Number(val) } : c));

    const total = useMemo(() => cart.reduce((s, c) => s + (c.cantidad * c.precio_dia), 0), [cart]);

    const handleRegistrarSalida = async () => {
        if (!clienteId) { setError('Selecciona un cliente.'); return; }
        if (cart.length === 0) { setError('Agrega al menos una tarima al carrito.'); return; }
        setSaving(true); setError('');
        try {
            // Create registro_salida
            const salidaRef = await addSalida({ cliente_id: clienteId, fecha, monto_total: total, presentacion: '' });
            const salidaId = salidaRef.id;

            // For each cart item: create detalle_salida, update detalle_entrada
            for (const item of cart) {
                await addDetalleSalida({
                    registro_salida_id: salidaId,
                    detalle_entrada_id: item.detalle.id,
                    cantidad_vendida: item.cantidad,
                    precio_dia: item.precio_dia,
                });
                // Update tarima
                const newVendido = item.detalle.cantidad_vendida + item.cantidad;
                const disponible = item.detalle.cantidad_recibida - newVendido - item.detalle.merma;
                await updateDetalle(item.detalle.id, {
                    cantidad_vendida: newVendido,
                    status: disponible <= 0 ? 'en_proceso' : 'en_proceso',
                });
                // Recalculate monto_total_productor on parent entrada
                // (done in real usage by querying all detalle_salidas for that entrada's tarimas)
            }

            setCart([]); setClienteId(''); setSuccess('¡Salida registrada exitosamente!');
            setTimeout(() => setSuccess(''), 4000);
        } catch (e) { setError(e.message); }
        finally { setSaving(false); }
    };

    const getEntrada = (id) => entradas.find(e => e.id === id);

    return (
        <div className="space-y-4">
            <SectionHeader title="Consolidador de Carga" />
            <ErrorBanner error={error} /><SuccessBanner message={success} />

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Left: available tarimas */}
                <div>
                    <p className="text-sm font-semibold text-slate-600 mb-3">Tarimas disponibles ({disponibles.length})</p>
                    <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-1">
                        {disponibles.length === 0 && <EmptyState icon={PackageSearch} message="No hay tarimas disponibles" />}
                        {disponibles.map(d => {
                            const variedad = variedades.find(v => v.id === d.variedad_id);
                            const disponible = d.cantidad_recibida - d.cantidad_vendida - d.merma;
                            const already = !!inCart(d.id);
                            return (
                                <div key={d.id} className={cn(
                                    "flex items-center justify-between p-3 rounded-xl border transition-all cursor-pointer",
                                    already ? "bg-green-50 border-green-200 opacity-60" : "bg-white border-slate-200 hover:border-green-300 hover:bg-green-50"
                                )} onClick={() => !already && addToCart(d)}>
                                    <div>
                                        <p className="font-mono text-sm font-semibold text-slate-800">Tarima #{d.tarima_no}</p>
                                        <p className="text-xs text-slate-500">{variedad?.nombre} · {d.presentacion}</p>
                                        <p className="text-xs text-slate-400">Disponible: <strong>{disponible} cajas</strong></p>
                                    </div>
                                    {already
                                        ? <CheckCircle className="w-5 h-5 text-green-500 flex-shrink-0" />
                                        : <ArrowRight className="w-5 h-5 text-slate-300 flex-shrink-0" />}
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Right: cart */}
                <div className="flex flex-col gap-4">
                    <div className="flex gap-3">
                        <Select label="Cliente" className="flex-1" options={clientes.map(c => ({ value: c.id, label: c.nombre }))} value={clienteId} onChange={e => setClienteId(e.target.value)} />
                        <Input label="Fecha" type="date" value={fecha} onChange={e => setFecha(e.target.value)} />
                    </div>

                    <div className="flex flex-col gap-2">
                        <p className="text-sm font-semibold text-slate-600">Carrito ({cart.length})</p>
                        {cart.length === 0 && <p className="text-sm text-slate-400 py-6 text-center border-2 border-dashed border-slate-200 rounded-xl">Selecciona tarimas de la izquierda</p>}
                        {cart.map(item => (
                            <div key={item.detalle.id} className="bg-slate-50 rounded-xl p-3 border border-slate-200">
                                <div className="flex items-center justify-between mb-2">
                                    <span className="font-mono text-sm font-semibold">Tarima #{item.detalle.tarima_no}</span>
                                    <button onClick={() => removeFromCart(item.detalle.id)} className="text-red-400 hover:text-red-600">
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                                <div className="grid grid-cols-2 gap-2">
                                    <Input label="Cajas a vender" type="number" value={item.cantidad} onChange={e => updateCartItem(item.detalle.id, 'cantidad', e.target.value)} />
                                    <Input label="Precio del día ($)" type="number" value={item.precio_dia} onChange={e => updateCartItem(item.detalle.id, 'precio_dia', e.target.value)} />
                                </div>
                                <p className="text-right text-sm font-semibold text-green-700 mt-1">
                                    Subtotal: ${(item.cantidad * item.precio_dia).toFixed(2)}
                                </p>
                            </div>
                        ))}
                    </div>

                    {cart.length > 0 && (
                        <div className="bg-green-50 rounded-xl p-4 border border-green-200">
                            <div className="flex justify-between items-center">
                                <span className="font-semibold text-green-800">Total</span>
                                <span className="text-2xl font-bold text-green-700">${total.toFixed(2)}</span>
                            </div>
                        </div>
                    )}

                    <Button loading={saving} onClick={handleRegistrarSalida} className="w-full py-3">
                        <ShoppingCart className="w-5 h-5" /> Registrar Salida
                    </Button>
                </div>
            </div>
        </div>
    );
}

/* ── Historial de Salidas ── */
export function SalidasSection({ clientes, variedades }) {
    const { data: salidas, loading, error } = useFirestore('registro_salidas');
    const { data: detalleSalidas } = useFirestore('detalle_salidas');
